import React from "react";
import { Formik } from "formik";

const form = () => (
  <div>

    <Formik>
      <form>
        <input name="firstName" type="text" />
        <input name="lastName" type="text" />
        <button type="submit">Submit</button>
      </form>
    </Formik>
  </div>
);

export default form;
